### 1. Board Class

```python
import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.setup_board()

    def setup_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.board[i][j] = -1  # Black piece

        for i in range(5, 8):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.board[i][j] = 1   # White piece

    def print_board(self):
        for row in self.board:
            print(' '.join(str(piece) for piece in row))
```

