class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def move(self, start_pos, end_pos, board):
        # Implement the logic for moving a piece
        if (end_pos[0] - start_pos[0]) == 2 or (end_pos[0] - start_pos[0]) == -2:
            mid_pos = ((start_pos[0] + end_pos[0]) // 2, (start_pos[1] + end_pos[1]) // 2)
            if board[mid_pos[0]][mid_pos[1]] != -self.color and board[mid_pos[0]][mid_pos[1]] != self.color:
                board[end_pos[0]][end_pos[1]] = board[start_pos[0]][start_pos[1]]
                board[mid_pos[0]][mid_pos[1]] = 0
        else:
            board[end_pos[0]][end_pos[1]] = board[start_pos[0]][start_pos[1]]

        if end_pos[0] == 0 or end_pos[0] == 7 and self.color == 1:
            self.is_king = True

    def can_capture(self, start_pos, end_pos, board):
        # Implement the logic for checking capture
        mid_pos = ((start_pos[0] + end_pos[0]) // 2, (start_pos[1] + end_pos[1]) // 2)
        if (end_pos[0] - start_pos[0]) == 2 or (end_pos[0] - start_pos[0]) == -2:
            return board[mid_pos[0]][mid_pos[1]] != -self.color and board[mid_pos[0]][mid_pos[1]] != self.color
        return False
